import React, { useState, useEffect } from 'react';
import { Box, Grid, Card, CardContent, Typography, Paper, CircularProgress } from '@mui/material';
import { People, Room, Assessment, CheckCircle } from '@mui/icons-material';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { useSnackbar } from 'notistack';
import { usersAPI, roomsAPI, verificationsAPI } from '../services/api';

export default function DashboardPage() {
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({
    totalUsers: 0,
    totalRooms: 0,
    totalVerifications: 0,
    completedVerifications: 0,
  });
  const [recentVerifications, setRecentVerifications] = useState([]);
  const [monthlyData, setMonthlyData] = useState([]);
  const { enqueueSnackbar } = useSnackbar();

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      setLoading(true);
      const [users, rooms, verifications] = await Promise.all([
        usersAPI.getAll(),
        roomsAPI.getAll(),
        verificationsAPI.getAll(),
      ]);

      // Statistiques
      setStats({
        totalUsers: users.length,
        totalRooms: rooms.length,
        totalVerifications: verifications.length,
        completedVerifications: verifications.filter(v => v.status === 'completed').length,
      });

      // 5 dernières vérifications
      setRecentVerifications(
        verifications
          .sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt))
          .slice(0, 5)
      );

      // Données mensuelles (6 derniers mois)
      const monthlyStats = generateMonthlyStats(verifications);
      setMonthlyData(monthlyStats);

    } catch (error) {
      enqueueSnackbar('Erreur lors du chargement des données', { variant: 'error' });
    } finally {
      setLoading(false);
    }
  };

  const generateMonthlyStats = (verifications) => {
    const months = ['Jan', 'Fév', 'Mar', 'Avr', 'Mai', 'Juin', 'Juil', 'Août', 'Sep', 'Oct', 'Nov', 'Déc'];
    const now = new Date();
    const data = [];

    for (let i = 5; i >= 0; i--) {
      const date = new Date(now.getFullYear(), now.getMonth() - i, 1);
      const monthVerifications = verifications.filter(v => {
        const vDate = new Date(v.createdAt);
        return vDate.getMonth() === date.getMonth() && vDate.getFullYear() === date.getFullYear();
      });

      data.push({
        mois: months[date.getMonth()],
        total: monthVerifications.length,
        complétées: monthVerifications.filter(v => v.status === 'completed').length,
      });
    }

    return data;
  };

  if (loading) {
    return (
      <Box sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '400px' }}>
        <CircularProgress />
      </Box>
    );
  }

  const statCards = [
    { title: 'Utilisateurs', value: stats.totalUsers, icon: <People />, color: '#1976d2' },
    { title: 'Salles', value: stats.totalRooms, icon: <Room />, color: '#2e7d32' },
    { title: 'Vérifications', value: stats.totalVerifications, icon: <Assessment />, color: '#ed6c02' },
    { title: 'Complétées', value: stats.completedVerifications, icon: <CheckCircle />, color: '#9c27b0' },
  ];

  return (
    <Box>
      <Typography variant="h4" gutterBottom sx={{ mb: 3 }}>
        Dashboard
      </Typography>

      {/* Statistiques */}
      <Grid container spacing={3} sx={{ mb: 4 }}>
        {statCards.map((stat) => (
          <Grid item xs={12} sm={6} md={3} key={stat.title}>
            <Card sx={{ bgcolor: stat.color, color: 'white' }}>
              <CardContent>
                <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <Box>
                    <Typography variant="body2" sx={{ opacity: 0.9 }}>
                      {stat.title}
                    </Typography>
                    <Typography variant="h4" sx={{ fontWeight: 'bold', mt: 1 }}>
                      {stat.value}
                    </Typography>
                  </Box>
                  <Box sx={{ fontSize: 48, opacity: 0.3 }}>
                    {stat.icon}
                  </Box>
                </Box>
              </CardContent>
            </Card>
          </Grid>
        ))}
      </Grid>

      <Grid container spacing={3}>
        {/* Graphique */}
        <Grid item xs={12} md={8}>
          <Paper sx={{ p: 3 }}>
            <Typography variant="h6" gutterBottom>
              Vérifications par mois
            </Typography>
            <ResponsiveContainer width="100%" height={300}>
              <BarChart data={monthlyData}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="mois" />
                <YAxis />
                <Tooltip />
                <Legend />
                <Bar dataKey="total" fill="#1976d2" name="Total" />
                <Bar dataKey="complétées" fill="#2e7d32" name="Complétées" />
              </BarChart>
            </ResponsiveContainer>
          </Paper>
        </Grid>

        {/* Dernières vérifications */}
        <Grid item xs={12} md={4}>
          <Paper sx={{ p: 3 }}>
            <Typography variant="h6" gutterBottom>
              Dernières vérifications
            </Typography>
            {recentVerifications.length === 0 ? (
              <Typography variant="body2" color="text.secondary">
                Aucune vérification
              </Typography>
            ) : (
              recentVerifications.map((verification) => (
                <Box
                  key={verification.id}
                  sx={{
                    p: 1.5,
                    mb: 1,
                    bgcolor: 'background.default',
                    borderRadius: 1,
                    borderLeft: 3,
                    borderColor: verification.status === 'completed' ? 'success.main' : 'warning.main',
                  }}
                >
                  <Typography variant="body2" sx={{ fontWeight: 'bold' }}>
                    {verification.room?.name || 'Salle inconnue'}
                  </Typography>
                  <Typography variant="caption" color="text.secondary">
                    {new Date(verification.createdAt).toLocaleDateString('fr-FR')}
                  </Typography>
                  <Typography variant="caption" sx={{ display: 'block', mt: 0.5 }}>
                    {verification.status === 'completed' ? '✅ Complétée' : '⏳ En cours'}
                  </Typography>
                </Box>
              ))
            )}
          </Paper>
        </Grid>
      </Grid>
    </Box>
  );
}
